    private List<Receipt> Receipts = new();
    private bool IsLoading;
    private string ActiveFilter = "Daily";
    private DateTime FilterFrom = DateTime.Today;
    private DateTime FilterTo = DateTime.Today;
    private int PageNumber = 1;
    private int PageSize = 10;
    private int TotalCount;

    private bool ShowDeleteConfirm;
    private Receipt? ReceiptToDelete;

    protected override async Task OnInitializedAsync()
    {
        await LoadReceipts();
    }

    private async Task LoadReceipts()
    {
        IsLoading = true;
        try
        {
            ApiResponse<PaginatedResult<Receipt>> apiResult;
            // If filter is Daily, Monthly, or Custom, pass date filter
            if (ActiveFilter == "Daily" || ActiveFilter == "Monthly" || (ActiveFilter == "Custom" && FilterFrom != default && FilterTo != default))
            {
                apiResult = await ReceiptService.SearchReceiptsByDateAsync(FilterFrom, FilterTo, PageNumber, PageSize);
            }
            else
            {
                apiResult = await ReceiptService.GetReceiptsAsync(new PaginationParams { PageNumber = PageNumber, PageSize = PageSize });
            }
            if (apiResult.Status == "success" && apiResult.Data != null)
            {
                Receipts = apiResult.Data.Items;
                TotalCount = apiResult.Data.TotalCount;
            }
            else
            {
                Receipts = new List<Receipt>();
                TotalCount = 0;
                await ToastService.ShowErrorAsync($"Failed to load receipts: {apiResult.Message}");
            }
        }
        catch (Exception ex)
        {
            await ToastService.ShowErrorAsync($"Failed to load receipts: {ex.Message}");
        }
        finally
        {
            IsLoading = false;
        }
    }

    private async Task SetDaily()
    {
        ActiveFilter = "Daily";
        FilterFrom = DateTime.Today;
        FilterTo = DateTime.Today;
        PageNumber = 1;
        await LoadReceipts();
    }

    private async Task SetMonthly()
    {
        ActiveFilter = "Monthly";
        FilterFrom = new DateTime(DateTime.Now.Year, DateTime.Now.Month, 1);
        FilterTo = FilterFrom.AddMonths(1).AddDays(-1);
        PageNumber = 1;
        await LoadReceipts();
    }

    private void SetCustom()
    {
        ActiveFilter = "Custom";
    }

    private async Task SearchCustom()
    {
        PageNumber = 1;
        await LoadReceipts();
    }

    private async Task ResetCustom()
    {
        FilterFrom = DateTime.Today.AddDays(-30);
        FilterTo = DateTime.Today;
        PageNumber = 1;
        await LoadReceipts();
    }

    private async Task OnPageChanged(int page)
    {
        PageNumber = page;
        await LoadReceipts();
    }

    private async Task OnPageSizeChanged(int size)
    {
        PageSize = size;
        PageNumber = 1;
        await LoadReceipts();
    }

    private void ViewReceipt(int id) => Navigation.NavigateTo($"/receipts/{id}");
    private void EditReceipt(int id) => Navigation.NavigateTo($"/receipts/{id}");

    private void ConfirmDelete(Receipt receipt)
    {
        ReceiptToDelete = receipt;
        ShowDeleteConfirm = true;
        StateHasChanged();
    }

    private async Task DeleteConfirmed()
    {
        Console.WriteLine("DeleteConfirmed called");
        if (ReceiptToDelete == null) return;
        ShowDeleteConfirm = false;
        try
        {
            var ok = await ReceiptService.DeleteReceiptAsync(ReceiptToDelete.ReceiptId);
            if (ok)
                await ToastService.ShowSuccessAsync("Receipt deleted successfully.");
            else
                await ToastService.ShowErrorAsync("Failed to delete receipt.");

            await LoadReceipts();
        }
        catch (Exception ex)
        {
            await ToastService.ShowErrorAsync($"Delete failed: {ex.Message}");
        }
        finally
        {
            ReceiptToDelete = null;
        }
    }

    private string GetStatusBadge(string status) => status switch
    {
        "Pending" => "badge-warning",
        "Received" => "badge-success",
        "Reconciled" => "badge-info",
        "Cancelled" => "badge-danger",
        _ => "badge-secondary"
    };

